// Parse Claude's JSON reply, re-validate against the scan enums, and shape the webhook response.
// Enum source of truth: src/lib/scans.ts + supabase/migrations/20260618130000_proj3_scans.sql
const ENUMS = {
  surface: ['gravel', 'lawn', 'soil', 'paved', 'mixed'],
  space_type: ['front_garden', 'back_garden', 'balcony', 'bed'],
  sun_exposure: ['full', 'partial', 'shade'],
};
const inSet = (v, k) => ENUMS[k].includes(v);

// Tolerant text extraction — works whether the upstream node is the AI 'Analyze Image'
// node (text on $json.text or $json.content) or a raw HTTP Request ($json.content[0].text).
function extractText(j) {
  if (typeof j.text === 'string') return j.text;
  const c = j.content;
  if (typeof c === 'string') return c;
  if (Array.isArray(c)) {
    const t = c.find((b) => b && b.type === 'text' && typeof b.text === 'string');
    if (t) return t.text;
  }
  if (Array.isArray(j.message?.content)) {
    const t = j.message.content.find((b) => b && b.type === 'text' && typeof b.text === 'string');
    if (t) return t.text;
  }
  return '{}';
}

let raw = extractText($json).trim();
// Defend against accidental markdown fences or prose around the JSON object.
const first = raw.indexOf('{');
const last = raw.lastIndexOf('}');
if (first !== -1 && last !== -1) raw = raw.slice(first, last + 1);

let ai;
try {
  ai = JSON.parse(raw);
} catch (e) {
  ai = { usable: false, confidence: 0 };
}

const fieldsValid =
  inSet(ai.surface, 'surface') &&
  inSet(ai.space_type, 'space_type') &&
  inSet(ai.sun_exposure, 'sun_exposure') &&
  Number.isInteger(ai.area_sqm) && ai.area_sqm >= 1 && ai.area_sqm <= 5000;

const usable =
  ai.usable === true &&
  ai.is_plantable_space === true &&
  (ai.confidence ?? 0) >= 0.5 &&
  fieldsValid;

// A photo is never rejected merely for 'not being a garden' — balconies/paved/gravel are valid.
const branch = usable ? 'ok' : 'fallback';
const status = usable ? 'ok' : (ai.usable === false ? 'rejected' : 'low_confidence');

const fields = usable
  ? {
      surface: ai.surface,
      space_type: ai.space_type,
      sun_exposure: ai.sun_exposure,
      area_sqm: ai.area_sqm,
    }
  : null;

return [
  {
    json: {
      branch,
      status,
      confidence: ai.confidence ?? 0,
      fields,
      message: usable
        ? 'Reading your space looked clear.'
        : 'We had trouble reading this photo — please fill in the details below.',
    },
  },
];
